import{c as t,Q as a,j as o,m as r}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Internal Users","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/internal-users.md","filePath":"guide/admin/internal-users.md","lastUpdated":1779094756000}'),s={name:"guide/admin/internal-users.md"};function n(i,e,l,c,d,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="internal-users" tabindex="-1">Internal Users <a class="header-anchor" href="#internal-users" aria-label="Permalink to &quot;Internal Users&quot;">​</a></h1><p>The <strong>Internal Users</strong> page is for managing platform operators — Infra Ops, Account Managers, QA Admins, and Platform Admins. See <a href="./../concepts/roles-and-permissions">Roles &amp; Permissions</a> for what each role can do.</p><h2 id="list-page" tabindex="-1">List page <a class="header-anchor" href="#list-page" aria-label="Permalink to &quot;List page&quot;">​</a></h2><h3 id="toolbar" tabindex="-1">Toolbar <a class="header-anchor" href="#toolbar" aria-label="Permalink to &quot;Toolbar&quot;">​</a></h3><p>The search bar is <strong>token-aware</strong>. Type free text to search across name and email, or use any of these tokens:</p><ul><li><code>status:active</code>, <code>status:invited</code>, <code>status:deactivated</code> — multi-choice.</li><li><code>role:infra_ops</code>, <code>role:account_manager</code>, <code>role:qa_admin</code>, <code>role:platform_admin</code> — multi-choice.</li><li><code>customer:&lt;customer&gt;</code> — filter by granted customer. Autocomplete.</li><li><code>instance:&lt;instance&gt;</code> — filter by granted instance. Autocomplete.</li></ul><p>Negation works too: <code>!status:deactivated</code> excludes deactivated users.</p><p>The placeholder shows an example: <code>Search — try role:account_manager customer:Acme</code>.</p><h3 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>Clickable link to user detail.</td></tr><tr><td><strong>Email</strong></td><td></td></tr><tr><td><strong>Roles</strong></td><td>Comma-separated list. Truncates with full list on hover.</td></tr><tr><td><strong>Scope</strong></td><td>Compact chips with <code>C:</code> for customer grants and <code>I:</code> for instance grants. Up to two visible; a &quot;+N more&quot; popover shows the rest.</td></tr><tr><td><strong>Status</strong></td><td>Active / Invited / Deactivated.</td></tr><tr><td><strong>Actions</strong></td><td>Row-level icons.</td></tr></tbody></table><h3 id="row-actions" tabindex="-1">Row actions <a class="header-anchor" href="#row-actions" aria-label="Permalink to &quot;Row actions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Action</th><th>Available when</th><th>Behaviour</th></tr></thead><tbody><tr><td><strong>Resend Invite</strong> (envelope)</td><td>Status is <code>invited</code></td><td>Confirms and resends the welcome email.</td></tr><tr><td><strong>Deactivate</strong> (power)</td><td>Status is <code>active</code></td><td>Confirms and revokes access immediately.</td></tr></tbody></table><h2 id="creating-a-new-user" tabindex="-1">Creating a new user <a class="header-anchor" href="#creating-a-new-user" aria-label="Permalink to &quot;Creating a new user&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Screenshot</p><p><em>Create user form (QA Admin selected):</em> the profile fields, the role checkbox group with QA Admin checked, plus both <strong>Customer Scope</strong> and <strong>Instance Scope</strong> pickers visible.</p></div><p>Click <strong>Add User</strong>. The form has three sections.</p><h3 id="profile" tabindex="-1">Profile <a class="header-anchor" href="#profile" aria-label="Permalink to &quot;Profile&quot;">​</a></h3><ul><li><strong>First name</strong> (required).</li><li><strong>Last name</strong> (optional).</li><li><strong>Email</strong> (required) — the invite email goes here. The user signs in via SSO and lands in the Console after accepting.</li></ul><h3 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h3><p>A checkbox group. Pick one or more. Picking <strong>Account Manager</strong> or <strong>QA Admin</strong> reveals the <strong>Customer Scope</strong> picker below. Picking <strong>QA Admin</strong> also reveals an <strong>Instance Scope</strong> picker.</p><h3 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h3><ul><li><strong>Customer Scope</strong> — appears for Account Manager / QA Admin. Pick the customers this user can read and operate on. <strong>An empty scope means no access</strong> — you must grant at least one customer.</li><li><strong>Instance Scope</strong> — appears for QA Admin. Pick the instances they can act on. Customer scope and instance scope are combined at query time.</li></ul><p>Click <strong>Create user</strong>. An invite email is sent and the user appears in the list as <code>invited</code>.</p><h2 id="user-detail-page" tabindex="-1">User detail page <a class="header-anchor" href="#user-detail-page" aria-label="Permalink to &quot;User detail page&quot;">​</a></h2><p>The detail page has read-only profile info and editable role and scope sections.</p><h3 id="profile-read-only" tabindex="-1">Profile (read-only) <a class="header-anchor" href="#profile-read-only" aria-label="Permalink to &quot;Profile (read-only)&quot;">​</a></h3><ul><li>Roles summary.</li><li>Last login (or &quot;Never&quot;).</li><li>Created date.</li><li>IDP User ID (last 8 chars).</li></ul><h3 id="roles-editable" tabindex="-1">Roles (editable) <a class="header-anchor" href="#roles-editable" aria-label="Permalink to &quot;Roles (editable)&quot;">​</a></h3><p>Same checkbox group as the create page. Edit locally then click <strong>Save</strong> (or <strong>Discard</strong> to revert). Scope sections respect the <strong>server-side</strong> role set — opening/closing scope pickers does not require saving the role change first.</p><h3 id="customer-scope-instance-scope-editable" tabindex="-1">Customer scope / Instance scope (editable) <a class="header-anchor" href="#customer-scope-instance-scope-editable" aria-label="Permalink to &quot;Customer scope / Instance scope (editable)&quot;">​</a></h3><p>Individual grant/revoke toggles. Changes apply immediately — there is no batched save here.</p><h3 id="notifications-read-only" tabindex="-1">Notifications (read-only) <a class="header-anchor" href="#notifications-read-only" aria-label="Permalink to &quot;Notifications (read-only)&quot;">​</a></h3><p>Grouped by category — Operations, Discrepancies, Billing, Infrastructure, General. Each row shows the event, a description, a &quot;Required&quot; tag (if compliance-enforced), and dots for in-app and email subscriptions.</p><p>This view is <strong>read-only</strong> — users manage their own subscriptions on their <a href="./../account/managing-your-account">Account</a> page.</p><h3 id="account-actions" tabindex="-1">Account actions <a class="header-anchor" href="#account-actions" aria-label="Permalink to &quot;Account actions&quot;">​</a></h3><ul><li><strong>Resend Invite</strong> — if the user is <code>invited</code>.</li><li><strong>Deactivate User</strong> — if the user is <code>active</code>. The confirmation modal warns &quot;They&#39;ll lose access immediately.&quot;</li></ul><p>After deactivation the page returns to the list.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Customer and instance dropdowns load lazily — they only fetch when you open them, keeping the list page snappy for operators who do not search by scope.</li><li>Role edits are local until you click <strong>Save</strong>. Scope edits apply immediately.</li><li>Reactivating a deactivated user is not a button on this page — you cannot &quot;un-deactivate&quot; by reopening the user. If a user needs to come back, recreate them.</li></ul>',38)])])}const g=t(s,[["render",n]]);export{p as __pageData,g as default};
